// ── Parse script outputs ───────────────────────────────────────────────────────
const SCRIPT_KEYS_DEFAULT=["LIVE_ANSWER","FOLLOW_UP_TEXT","BE_USEFUL_TEXT"];
function parseScripts(raw,keys){
  const result={};
  (keys||SCRIPT_KEYS_DEFAULT).forEach((key,i,arr)=>{
    const next=arr[i+1];
    const start=raw.indexOf(key+":");
    if(start===-1){result[key]="";return;}
    const end=next?raw.indexOf(next+":"):raw.length;
    result[key]=raw.slice(start+key.length+1,end>start?end:raw.length).trim();
  });
  return result;
}

// ── Shared: BucketScriptScreen ────────────────────────────────────────────────
// Reused by all 9 buckets. Each bucket passes its own bucket id + labels.
function BucketScriptScreen({bucket,inputs,setFlag,flagKey,onNext,onBack,titleEmoji,title,titleEs,strategyNote,strategyNoteEs}){
  const s=useSp();
  const [scripts,setScripts]=useState(null);
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState(false);
  const [tracked,setTracked]=useState(0);

  async function generate(){
    setLoading(true);setError(false);
    try{
      const raw=await genBucketScripts(inputs,bucket,s);
      setScripts(parseScripts(raw));
    }catch{setError(true);}
    setLoading(false);
  }
  useEffect(()=>{generate();},[]);

  const scriptDefs=[
    {key:"LIVE_ANSWER",   label:s?"📞 Guión de Llamada en Vivo":"📞 Live Call Script",   hint:s?"Para cuando responden.":"For when they pick up."},
    {key:"FOLLOW_UP_TEXT",label:s?"💬 Texto de Seguimiento":"💬 Follow-Up Text",         hint:s?"Envía si no responden la llamada.":"Send if they don't answer."},
    {key:"BE_USEFUL_TEXT",label:s?"🤝 Si Ya Contrataron a Alguien":"🤝 If They Already Hired Someone", hint:s?"No intentes recuperar el trabajo. Sé útil. Gana la próxima.":"Don't chase the job. Be useful. Earn the next one."},
  ];

  return (
    <div>
      <SectionHeader emoji={titleEmoji} title={s?titleEs:title} subtitle={s?"Guiones personalizados para tu oficio y ciudad.":"Personalized scripts for your trade and city."}/>

      {/* Strategy callout */}
      <Card style={{background:"#FEF9EC",border:"2px solid "+YELLOW}}>
        <div style={{fontWeight:800,color:NAVY,fontSize:14,marginBottom:10}}>{s?"La estrategia":"The strategy"}</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
          {[
            {e:"✅",t:s?"Reconoce el fallo":"Own the miss"},
            {e:"✅",t:s?"Explica el arreglo":"Explain the fix"},
            {e:"✅",t:s?"Elimina la presión":"Remove pressure"},
            {e:"✅",t:s?"Sé útil":"Be useful"},
          ].map((item,i)=>(
            <div key={i} style={{display:"flex",gap:8,alignItems:"center",fontSize:13,fontWeight:600,color:NAVY}}>
              <span>{item.e}</span><span>{item.t}</span>
            </div>
          ))}
        </div>
        <div style={{background:NAVY,borderRadius:10,padding:"10px 14px"}}>
          <span style={{color:YELLOW,fontWeight:800,fontSize:13,fontStyle:"italic"}}>
            {s?"No buscan otro precio. Buscan al Pro en quien puedan confiar para siempre.":"They are not looking for another quote. They are looking for their Pro for life. Be that person."}
          </span>
        </div>
        {(strategyNote||strategyNoteEs)&&(
          <p style={{fontSize:12,color:GRAY600,margin:"10px 0 0",lineHeight:1.6,fontStyle:"italic"}}>
            💡 {s?(strategyNoteEs||strategyNote):strategyNote}
          </p>
        )}
      </Card>

      {/* Scripts */}
      {scriptDefs.map(sd=>(
        <div key={sd.key} style={{marginBottom:4}}>
          <div style={{fontWeight:700,color:NAVY,fontSize:14,marginBottom:2}}>{sd.label}</div>
          <div style={{fontSize:12,color:GRAY400,marginBottom:6}}>{sd.hint}</div>
          <ScriptBox text={scripts?scripts[sd.key]:""} loading={loading&&!scripts} error={error&&!loading} onRetry={generate}/>
        </div>
      ))}

      {/* Tracker */}
      {scripts&&(
        <Card style={{background:NAVY}}>
          <h3 style={{color:YELLOW,fontWeight:900,fontSize:16,margin:"0 0 12px"}}>📊 {s?"Seguimiento":"Tracker"}</h3>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
            <div style={{color:WHITE,fontSize:13}}>{s?"Contactos de recuperación enviados:":"Recovery contacts sent:"}</div>
            <div style={{color:YELLOW,fontWeight:900,fontSize:28,lineHeight:1}}>{tracked}</div>
          </div>
          <Btn onClick={()=>{const n=tracked+1;setTracked(n);if(flagKey)setFlag(flagKey,n);}} style={{width:"100%",justifyContent:"center"}}>
            + {s?"Registrar Contacto":"Log a Recovery Contact"}
          </Btn>
        </Card>
      )}
      <BottomNav onBack={onBack} onNext={()=>onNext(picked)} nextDisabled={!picked}/>
    </div>
  );
}

// ── Shared: BucketFixScreen ───────────────────────────────────────────────────
// Each bucket's "fix" screen — pick the operational fix, then proceed to scripts.
function BucketFixScreen({bucket,inputs,setInputs,onNext,onBack,titleEmoji,title,titleEs,warning,warningEs,fixes}){
  const s=useSp();
  const fixKey="fix_"+bucket;
  return (
    <div>
      <SectionHeader emoji={titleEmoji} title={s?titleEs:title}
        subtitle={s?"Elige el arreglo que implementarás esta semana.":"Pick the fix you will implement this week."}/>
      {(warning||warningEs)&&(
        <div style={{background:"#FEF9EC",border:"2px solid "+YELLOW,borderRadius:14,padding:"14px 16px",marginBottom:20}}>
          <p style={{fontSize:13,color:NAVY,fontWeight:700,margin:"0 0 4px"}}>⚠️ {s?"El orden importa":"Order matters"}</p>
          <p style={{fontSize:13,color:GRAY600,lineHeight:1.7,margin:0}}>{s?(warningEs||warning):warning}</p>
        </div>
      )}
      <div style={{display:"flex",flexDirection:"column",gap:12,marginBottom:20}}>
        {fixes.map(fix=>(
          <div key={fix.id} onClick={()=>setInputs(p=>({...p,[fixKey]:fix.id}))}
            style={{background:inputs[fixKey]===fix.id?"#EFF6FF":WHITE,
              border:"2px solid "+(inputs[fixKey]===fix.id?NAVY:GRAY200),
              borderRadius:14,padding:"16px 18px",cursor:"pointer",display:"flex",gap:14,alignItems:"flex-start"}}>
            <span style={{fontSize:26,flexShrink:0}}>{fix.emoji}</span>
            <div style={{flex:1}}>
              <div style={{fontWeight:800,color:NAVY,fontSize:14,marginBottom:4}}>{s?(fix.titleEs||fix.title):fix.title}</div>
              <div style={{fontSize:12,color:GRAY600,lineHeight:1.6}}>{s?(fix.descEs||fix.desc):fix.desc}</div>
            </div>
            {inputs[fixKey]===fix.id&&
              <div style={{width:24,height:24,borderRadius:"50%",background:NAVY,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:2}}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={WHITE} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
              </div>
            }
          </div>
        ))}
      </div>
      <BottomNav onBack={onBack} onNext={onNext}/>
    </div>
  );
}

// ── Shared: try import from Week 1/2 ─────────────────────────────────────────
function getImportData(){
  try{
    // Try Week 1
    const w1=JSON.parse(localStorage.getItem("hbc_week1_progress")||"{}");
    const w2flags=JSON.parse(localStorage.getItem("hcp_nd_inputs")||"{}");
    return {
      proName:(w2flags.proName)||(w1.answers&&w1.answers.name)||"",
      trade:(w2flags.trade)||"",
      city:(w2flags.city)||(w1.answers&&w1.answers.area)||"",
      businessName:(w2flags.businessPageName)||(w1.answers&&w1.answers.business)||"",
    };
  }catch{return null;}
}

// ── UI Primitives (match Week 2 exactly) ─────────────────────────────────────
function Card({children,style}){return <div style={{background:WHITE,borderRadius:16,padding:28,boxShadow:"0 4px 24px rgba(0,41,66,0.08)",marginBottom:20,...style}}>{children}</div>;}
function Btn({children,onClick,variant,style,disabled}){
  const v=variant||"primary";
  const base={border:"none",borderRadius:10,minHeight:44,padding:"0 24px",fontWeight:700,fontSize:15,cursor:disabled?"not-allowed":"pointer",transition:"all 0.2s",display:"inline-flex",alignItems:"center",justifyContent:"center",gap:6};
  const vars={primary:{background:YELLOW,color:NAVY},secondary:{background:NAVY,color:WHITE},success:{background:GREEN,color:WHITE},ghost:{background:"transparent",color:GRAY400,border:"1.5px solid "+GRAY200}};
  return <button onClick={onClick} disabled={!!disabled} style={{...base,...vars[v]||vars.primary,opacity:disabled?0.45:1,...style}}>{children}</button>;
}
function BottomNav({onBack,onNext,nextLabel,nextDisabled,backLabel}){
  const s=useSp();
  return <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:28,paddingTop:20,borderTop:"1px solid "+GRAY200}}>
    <Btn variant="ghost" onClick={onBack} style={{fontSize:14,minWidth:120}}>{backLabel||(s?"← Atrás":"← Back")}</Btn>
    {onNext&&<Btn onClick={onNext} disabled={nextDisabled} style={{fontSize:14,minWidth:120}}>{nextLabel||(s?"Siguiente →":"Next →")}</Btn>}
  </div>;
}
function SectionHeader({title,subtitle,emoji}){
  return <div style={{marginBottom:20}}>
    <div style={{fontSize:32,marginBottom:8}}>{emoji}</div>
    <h2 style={{fontSize:22,fontWeight:800,color:NAVY,margin:0}}>{title}</h2>
    {subtitle&&<p style={{color:GRAY600,margin:"8px 0 0",fontSize:14,lineHeight:1.6}}>{subtitle}</p>}
  </div>;
}
function FormField({label,hint,value,onChange,placeholder,rows,type}){
  return <div style={{marginBottom:16}}>
    <label style={{display:"block",fontWeight:700,color:NAVY,fontSize:14,marginBottom:4}}>{label}</label>
    {hint&&<p style={{margin:"0 0 6px",fontSize:12,color:GRAY400}}>{hint}</p>}
    {rows>1
      ?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder||""} rows={rows} style={{width:"100%",boxSizing:"border-box",border:"2px solid "+GRAY200,borderRadius:10,padding:"10px 14px",fontSize:14,color:GRAY800,fontFamily:"inherit",resize:"vertical",outline:"none"}}/>
      :<input type={type||"text"} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder||""} style={{width:"100%",boxSizing:"border-box",border:"2px solid "+GRAY200,borderRadius:10,padding:"10px 14px",fontSize:14,color:GRAY800,fontFamily:"inherit",outline:"none"}}/>
    }
  </div>;
}
function LoadingDots(){
  return <div style={{display:"flex",alignItems:"center",gap:16,padding:"12px 0",color:GRAY400,fontSize:13}}>
    <style>{"@keyframes blink{0%,80%,100%{opacity:.2}40%{opacity:1}}"}</style>
    {[0,1,2].map(i=><div key={i} style={{width:8,height:8,borderRadius:"50%",background:YELLOW,animation:"blink 1.2s infinite",animationDelay:i*.2+"s"}}/>)}
    <span>Generating...</span>
  </div>;
}

function GeneratingView({title,subtitle,scriptLabels,messages:customMessages}){
  const s=useContext(LangCtx)==="es";
  const defaultMessages=s?[
    "Analizando tu oficio y ciudad...",
    "Personalizando tu plantilla...",
    "Aplicando principios del Pro de por vida...",
    "Eliminando relleno de ventas...",
    "Casi listo...",
  ]:[
    "Analyzing your trade and city...",
    "Personalizing your template...",
    "Applying Pro for life principles...",
    "Removing sales filler...",
    "Almost ready...",
  ];
  const messages=customMessages||defaultMessages;
  const [msgIdx,setMsgIdx]=useState(0);
  useEffect(()=>{
    const t=setInterval(()=>setMsgIdx(i=>(i+1)%messages.length),1800);
    return()=>clearInterval(t);
  },[]);

  const defaultLabels=s?[
    "\u{1F4DE} Gui\u00F3n de Llamada en Vivo",
    "\u{1F4AC} Texto de Seguimiento",
    "\u{1F91D} Si Ya Contrataron a Alguien",
  ]:[
    "\u{1F4DE} Live Call Script",
    "\u{1F4AC} Follow-Up Text",
    "\u{1F91D} If They Already Hired Someone",
  ];
  const labels=scriptLabels||defaultLabels;

  return (
    <div style={{minHeight:360,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",textAlign:"center",padding:"36px 24px"}}>
      <style>{"@keyframes shimmer{0%{background-position:-400px 0}100%{background-position:400px 0}}"}</style>

      {/* Animated dots */}
      <div style={{display:"flex",gap:10,marginBottom:20}}>
        {[0,1,2].map(i=>(
          <div key={i} style={{width:14,height:14,borderRadius:"50%",background:YELLOW,animation:"blink 1.2s infinite",animationDelay:i*0.2+"s"}}/>
        ))}
      </div>

      <div style={{fontWeight:900,color:NAVY,fontSize:20,marginBottom:8}}>
        {title||(s?"Generando guiones...":"Generating your scripts...")}
      </div>
      <div style={{fontSize:14,color:GRAY400,marginBottom:32,minHeight:22,transition:"opacity 0.4s"}}>
        {messages[msgIdx]}
      </div>

      {/* Skeleton script cards */}
      {labels.map((label,i)=>(
        <div key={i} style={{width:"100%",maxWidth:560,background:GRAY50,border:"1.5px solid "+GRAY200,borderRadius:12,padding:"16px 18px",marginBottom:12,textAlign:"left"}}>
          <div style={{fontWeight:700,color:NAVY,fontSize:13,marginBottom:12}}>{label}</div>
          {["80%","95%","70%","85%","55%"].slice(0,i===1?2:i===2?2:4).map((w,j)=>(
            <div key={j} style={{height:11,borderRadius:6,marginBottom:9,width:w,
              background:"linear-gradient(90deg,"+GRAY200+" 25%,"+GRAY100+" 50%,"+GRAY200+" 75%)",
              backgroundSize:"400px 100%",animation:"shimmer 1.4s infinite",animationDelay:j*0.12+"s"}}/>
          ))}
        </div>
      ))}
    </div>
  );
}
function ScriptBox({label,text,loading,error,onRetry}){
  const [c,sC]=useState(false);
  function copy(){
    try{const el=document.createElement("textarea");el.value=text;el.style.cssText="position:fixed;opacity:0";document.body.appendChild(el);el.select();document.execCommand("copy");document.body.removeChild(el);}catch(e){}
    sC(true);setTimeout(()=>sC(false),2000);
  }
  return <div style={{background:GRAY50,border:"1.5px solid "+GRAY200,borderRadius:12,padding:16,marginBottom:14}}>
    {label&&<div style={{fontSize:11,fontWeight:700,color:GRAY400,marginBottom:6,textTransform:"uppercase",letterSpacing:"0.05em"}}>{label}</div>}
    {loading&&<LoadingDots/>}
    {error&&!loading&&<div style={{display:"flex",alignItems:"center",gap:10,color:RED,fontSize:13}}><span>Could not generate. </span><button onClick={onRetry} style={{background:"none",border:"none",color:NAVY,fontWeight:700,cursor:"pointer",textDecoration:"underline"}}>Try again</button></div>}
    {!loading&&!error&&text&&<>
      <pre style={{margin:"0 0 12px",fontSize:16,color:GRAY800,lineHeight:1.8,whiteSpace:"pre-wrap",fontFamily:"inherit"}}>{text}</pre>
      <Btn onClick={copy} variant={c?"success":"primary"} style={{fontSize:13}}>{c?"✓ Copied!":"📋 Copy"}</Btn>
    </>}
  </div>;
}

// ── Side Nav ──────────────────────────────────────────────────────────────────
function SideNav({current,onNavigate,flags,inputs}){
  const s=useSp();
  const activeSection=NAV.find(n=>n.phases.includes(current));
  const done={
    customers:flags.t3_customers_done,
    estimates:flags.t3_estimates_done,
    calls:flags.t3_calls_done,
    amplify:flags.topFunnelDone&&flags.midFunnelDone&&flags.bottomFunnelDone,
    scorecard:false,
  };
  return (
    <div style={{width:260,flexShrink:0,background:NAVY,minHeight:"100%",padding:"24px 0",boxSizing:"border-box"}}>
      {NAV.map(sec=>{
        const isA=activeSection&&activeSection.id===sec.id;
        const isDone=done[sec.id];
        const subMap=s?sec.subEs:sec.sub;
        return (
          <div key={sec.id}>
            <div onClick={()=>onNavigate(sec.id)}
              style={{display:"flex",alignItems:"center",gap:12,padding:"14px 20px",cursor:"pointer",
                borderLeft:isA?"5px solid "+YELLOW:"5px solid transparent",
                background:isA?"rgba(255,255,255,0.08)":"transparent"}}>
              <span style={{fontSize:20,flexShrink:0,opacity:isA?1:isDone?0.9:0.5}}>{sec.emoji}</span>
              <div style={{flex:1}}>
                <span style={{fontWeight:900,fontSize:15,color:isA?YELLOW:isDone?GREEN:WHITE,lineHeight:1.2}}>
                  {s?sec.labelEs:sec.label}
                </span>
              </div>
            </div>
            {isA&&sec.id==="assessment"&&Object.keys(subMap).length>0&&(
              Object.entries(subMap).map(([subId,subLabel])=>{
                const stepMap={"assess_calls":"call_handling","assess_estimates":"estimates","assess_ltv":"ltv","assess_report":"results"};
                const targetStep=stepMap[subId];
                const completedSteps=["plinko","call_handling","call_handling_detail","call_config","call_sliders","estimates","ltv","results"];
                const currentStepIdx=completedSteps.indexOf(inputs?.assessmentStep||"plinko");
                const targetStepIdx=completedSteps.indexOf(targetStep);
                const isDoneItem=inputs?.assessmentComplete&&targetStep==="results"||currentStepIdx>targetStepIdx;
                const isActiveItem=targetStep&&(inputs?.assessmentStep===targetStep||(targetStep==="results"&&inputs?.assessmentComplete));
                return (
                  <div key={subId} onClick={()=>onNavigate("assessment",subId)}
                    style={{display:"flex",alignItems:"center",gap:10,padding:"9px 20px 9px 40px",cursor:"pointer",
                      background:isActiveItem?"rgba(254,183,5,0.15)":"transparent"}}>
                    {isDoneItem
                      ?<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,background:GREEN,display:"flex",alignItems:"center",justifyContent:"center"}}>
                          <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke={WHITE} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                        </div>
                      :isActiveItem
                        ?<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,background:YELLOW,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 0 0 3px rgba(255,183,6,0.3)"}}>
                            <div style={{width:8,height:8,borderRadius:"50%",background:NAVY}}/>
                          </div>
                        :<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,border:"2px solid "+GRAY400}}/>
                    }
                    <span style={{fontSize:13,fontWeight:isActiveItem?800:500,color:isDoneItem?GREEN:isActiveItem?YELLOW:WHITE}}>
                      {subLabel}
                    </span>
                  </div>
                );
              })
            )}
            {isA&&sec.id!=="assessment"&&(sec.subPhases||sec.phases).map((p,i)=>{
              const subList=sec.subPhases||sec.phases;
              const isActive=current===p;
              const isPast=sec.phases.indexOf(current)>sec.phases.indexOf(p);
              return (
                <div key={p} onClick={()=>onNavigate(p)}
                  style={{display:"flex",alignItems:"center",gap:10,padding:"9px 20px 9px 40px",cursor:"pointer",
                    background:isActive?"rgba(254,183,5,0.15)":"transparent"}}>
                  {isPast
                    ?<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,background:GREEN,display:"flex",alignItems:"center",justifyContent:"center"}}>
                        <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke={WHITE} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                      </div>
                    :isActive
                      ?<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,background:YELLOW,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 0 0 3px rgba(255,183,6,0.3)"}}>
                          <div style={{width:8,height:8,borderRadius:"50%",background:NAVY}}/>
                        </div>
                      :<div style={{width:20,height:20,borderRadius:"50%",flexShrink:0,border:"2px solid "+GRAY400}}/>
                  }
                  <span style={{fontSize:13,fontWeight:isActive?800:500,color:isPast?GREEN:isActive?YELLOW:WHITE}}>
                    {subMap[p]||p}
                  </span>
                </div>
              );
            })}
          </div>
        );
      })}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// TOP 3 PLAYS — SHARED: Script generator
// ─────────────────────────────────────────────────────────────────────────────
async function genTop3Script(inp, bucket, isEs){
  const isEmail = bucket==="t3_customers" && inp.t3CustomerBlastType==="email";
  // Use mock in preview sandbox
  if(isApiBlocked()){
    await new Promise(r=>setTimeout(r,2200));
    if(isEmail){
      const bizN=inp.businessName||"your business";
      const svc=inp.trade||"home services";
      const rawOfr=inp.t3EmailOffer||"";
      const ph=inp.t3EmailPhone||"";
      // Use the same CHIP_MAP as the real prompt so mock reflects actual selection
      const MOCK_CHIP_MAP={
        "Small issues are always cheaper to fix before they turn into emergencies":"Small issues are always cheaper to fix before they become emergencies. I wanted to reach out before something comes up.",
        "Getting ahead of this now saves money compared to waiting":"Getting ahead of this now is a lot less expensive than dealing with it after something breaks. Wanted to give you a heads up.",
        "We are reaching out to existing customers before opening up new bookings":"We are reaching out to our existing customers before we open up new bookings. Wanted to make sure you had first shot.",
        "Catching this early is a lot less expensive than dealing with it later":"Catching this now is a lot less expensive than dealing with it later. Wanted to reach out while we have some availability.",
        "Pre-holiday slots are filling up and I wanted to reach out to you first":"Pre-holiday slots are filling up and I wanted to make sure you were taken care of before we fill up.",
        "This time of year books fast and I wanted to make sure you are taken care of":"This time of year tends to book fast. Wanted to reach out to make sure you are taken care of.",
        "It has been a while and I wanted to reach out before things get busy":"It has been a while and I wanted to reach out before things get busy for the season.",
        "We are booking out and I wanted to give existing customers first shot":"We are starting to book out and I wanted to give our existing customers first shot.",
        "We have some availability coming up and thought of your project":"We have some availability coming up and your project came to mind. Wanted to reach out.",
        "Material costs are stable right now and worth locking in":"Material costs are stable right now and it is a good time to lock in before that changes.",
        "We are booking projects for the next few weeks and wanted to reach out":"We are booking projects for the next few weeks and wanted to reach out to past customers first.",
        "If you know anyone who needs this work done we have a referral bonus available":"If you know anyone who could use this kind of work, we have a referral bonus available right now.",
        "We have some openings this week and wanted to reach out to you first":"We have some openings this week and wanted to reach out to you first before filling them up.",
        "We are booking out and wanted to give existing customers priority":"We are starting to book out and wanted to give existing customers priority before we open up.",
        "Now is a good time to get ahead of it before things get busy":"Now is a good time to get ahead of this before things get busy.",
        "We are reaching out to past customers before we open up new bookings":"We are reaching out to past customers before we open up new bookings. Wanted to make sure you had first access.",
      };
      const ofrHint=MOCK_CHIP_MAP[rawOfr]||rawOfr||"We have some availability this week and wanted to reach out.";
      const isMechTrade=svc.toLowerCase().includes("hvac")||svc.toLowerCase().includes("plumb")||svc.toLowerCase().includes("electr")||svc.toLowerCase().includes("heat")||svc.toLowerCase().includes("cool")||svc.toLowerCase().includes("gas");
      return {raw:"",result:{
        SUBJECT_LINE:isMechTrade?"Maintenance reminder from "+bizN:"Service reminder from "+bizN,
        EMAIL_BODY:"Hi,\n\n"+ofrHint+"\n\n"+(isMechTrade?"Routine maintenance helps catch small issues early and keeps everything running the way it should.":"It has been a while and we wanted to make sure you are taken care of.")+"\n\nJust mention this email when you book and we will take care of the rest."+(ph?"\n\nYou can also reach us at "+ph+" if you prefer.":"")+"\n\nTalk soon,\nThe "+bizN+" Team",
      },labels:["SUBJECT_LINE","EMAIL_BODY"]};
    }
    const m=MOCK_SCRIPTS[bucket]||MOCK_SCRIPTS.t3_calls;
    return {raw:"",result:m.result,labels:m.labels};
  }

  // Email blast — calls Anthropic API directly (artifact pattern)
  if(isEmail){
    const bizN=inp.businessName||"the business";
    const svc=inp.trade||"home services";
    const rawOffer=inp.t3EmailOffer||"";
    const ph=inp.t3EmailPhone||"call us";

    // Map chip text to a prompt instruction so the AI uses it contextually, not verbatim
    const CHIP_MAP={
      // Mechanical
      "Small issues are always cheaper to fix before they turn into emergencies":"risk framing, small unaddressed issues can escalate into costly emergency repairs, acting now is the financially smart move",
      "Getting ahead of this now saves money compared to waiting":"loss aversion framing, preventative maintenance now is significantly less expensive than emergency repair later",
      "We are reaching out to existing customers before opening up new bookings":"priority access, contacting past customers before opening availability to new bookings",
      "Catching this early is a lot less expensive than dealing with it later":"loss aversion framing, catching issues early prevents significantly higher costs later",
      // Recurring
      "Pre-holiday slots are filling up and I wanted to reach out to you first":"seasonal deadline, pre-holiday schedule filling up, reaching out to existing customers first",
      "This time of year books fast and I wanted to make sure you are taken care of":"seasonal demand framing, this time of year tends to book quickly and existing customers get priority",
      "It has been a while and I wanted to reach out before things get busy":"time-based reminder, reconnecting before the busy season, making sure they are taken care of",
      "We are booking out and I wanted to give existing customers first shot":"priority access framing, giving existing customers first shot before the schedule fills",
      // One-time
      "We have some availability coming up and thought of your project":"availability framing, opening in the schedule and this project came to mind",
      "Material costs are stable right now and worth locking in":"price protection, material costs are stable right now and worth locking in before they change",
      "We are booking projects for the next few weeks and wanted to reach out":"forward booking, scheduling projects for coming weeks and reaching out to past customers first",
      "If you know anyone who needs this work done we have a referral bonus available":"referral hook, referral bonus available for anyone they refer",
      // Default
      "We have some openings this week and wanted to reach out to you first":"availability plus priority, openings this week and reaching out to existing customers first",
      "We are booking out and wanted to give existing customers priority":"priority access, giving past customers first access before opening to new bookings",
      "Now is a good time to get ahead of it before things get busy":"seasonal framing, good time to act before the busy season",
      "We are reaching out to past customers before we open up new bookings":"priority access, contacting past customers before opening availability to new ones",
      // ES
      "Los espacios pre-temporada se estan llenando y queria contactarte primero":"fecha limite estacional, agenda pre-temporada llenandose, contactando a clientes existentes primero",
      "Esta epoca del ano se reserva rapido y queria asegurarme de que estes atendido":"demanda estacional, esta epoca tiende a reservarse rapido y los clientes existentes tienen prioridad",
      "Ha pasado un tiempo y queria contactarte antes de que las cosas se pongan ocupadas":"recordatorio temporal, ha pasado un tiempo y es buen momento para reconectar antes de la temporada alta",
      "Estamos llenando la agenda y quise dar prioridad a los clientes existentes":"acceso prioritario, dando prioridad a clientes existentes antes de abrir la agenda",
      "Los problemas pequenos siempre son mas baratos de arreglar antes de convertirse en emergencias":"encuadre de riesgo, los problemas sin atender pueden escalar a reparaciones de emergencia costosas",
      "Adelantarse a esto ahora ahorra dinero comparado con esperar":"encuadre de perdida, el mantenimiento preventivo ahora es mucho menos costoso que una reparacion de emergencia",
      "Estamos contactando a clientes existentes antes de abrir nuevas reservas":"acceso prioritario, contactando a clientes anteriores antes de abrir disponibilidad a nuevos",
      "Atenderlo temprano es mucho menos costoso que esperar a que se convierta en un problema mayor":"encuadre de perdida, atender esto temprano previene costos significativamente mas altos despues",
      "Tenemos disponibilidad proxima y pensamos en tu proyecto":"disponibilidad, espacio en la agenda y este proyecto vino a la mente",
      "Los costos de materiales estan estables ahora y vale la pena asegurar":"proteccion de precio, los costos de materiales estan estables y vale asegurar antes de que cambien",
      "Estamos agendando proyectos para las proximas semanas y quisimos contactarte":"reserva anticipada, agendando proyectos para las proximas semanas y contactando a clientes anteriores primero",
      "Si conoces a alguien que necesite este trabajo tenemos un bono de referidos disponible":"bono de referidos disponible para cualquier persona que recomienden",
      "Tenemos algunos espacios esta semana y quisimos contactarte primero":"disponibilidad mas prioridad, espacios esta semana y contactando a clientes existentes primero",
      "Estamos llenando la agenda y quisimos dar prioridad a los clientes existentes":"acceso prioritario, dando a los clientes anteriores primer acceso",
      "Es buen momento para adelantarse antes de que las cosas se pongan ocupadas":"encuadre estacional, buen momento para actuar antes de la temporada alta",
      "Estamos contactando a clientes anteriores antes de abrir nuevas reservas":"acceso prioritario, contactando a clientes anteriores antes de abrir disponibilidad a nuevos",
    };
    const ofr=CHIP_MAP[rawOffer]||rawOffer||"limited availability this week";

    const system=`Write a re-engagement email for past customers that drives bookings and feels like part of the service, not marketing.

Business details:
Business name: ${bizN}
Primary service: ${svc}
Offer needed to be redeemed by end of next business day: ${ofr}
Phone number: ${ph}
Approximate time since last service: use "it's been a while"
Note: An online booking button will be inserted into the email. Do not include or reference a raw URL.

Do not assume or reference any industry beyond the primary service provided.

Subject line requirements:
Use transactional or service-update language that feels expected and operational.
Approved patterns include: Service reminder, Maintenance reminder, Recommended service check, Your service follow-up
Avoid hype, urgency for urgency's sake, or curiosity-only phrasing.
Do not use: Welcome back, Act now, Don't miss out, You'll want to see this.

Include the company name or service only when clarity requires it:
If the sender name clearly identifies the company and the last service was recent, do not include the company name in the subject line.
If it has been a long time since the last service, nine months or more, or if sender identity may be unclear, append identity at the end: Service reminder from ${bizN}
Keep the subject line under 55 characters, neutral, trustworthy, and non-salesy.
Return only one subject line.

Email body rules:
Generate 1 complete email body that is ready to send with no edits.
The email must start with a greeting. Prioritize "Hi," or "Hello,"

Email structure:
First line is written only to function as preview text and should clearly explain why this message matters now.
One short paragraph explaining the value of the service in plain, customer-friendly language.
Clear presentation of the offer, positioned as appreciation, not a promotion. Clearly explain how to receive it: "Just mention this email when you book."
Strong call to action that encourages the customer to book using the booking button in the email, with the phone number as a secondary option.
Confident, friendly closing from the business team.

Sign-off rules:
Use only one company reference in the closing.
Do not repeat the business name in both a closing sentence and the signature.
The sign-off should be short, natural, and non-repetitive.

Additional constraints:
Keep the full email under 200 words.
Use short paragraphs, one to two sentences max.
Optimize for mobile reading.
Do not mention marketing, campaigns, automation, or internal tools.
Do not include emojis.
Do not reference links, URLs, or clicking text links. Assume a booking button will be present.

Writing style rules:
Write like a real business owner or office manager sending a personal note, not a marketing department sending a campaign.
Plain text style. No bullet points, no bold text, no headers inside the email body.
Do not use em dashes or en dashes.
Use periods and commas only.
Avoid polished marketing language.
Avoid company mission, values, or brand storytelling.
Assume the customer already knows and trusts the business.
Be practical, clear, and direct.
If the urgency hook references risk, cost of inaction, or potential damage, lead with that consequence naturally and honestly. Do not soften it into promotional language. Frame it as something a trusted advisor would say, not a marketer.
If the urgency hook references availability or timing, keep the scarcity specific and believable. A specific day or window is more credible than a vague claim.

Output rules:
Return only: [SUBJECT_LINE] then the subject line, then [EMAIL_BODY] then the email body.
Do not include explanations, multiple options, or formatting notes.
The result should be a polished, best-practice email that can be sent immediately.`
      +(isEs?"\n\nWrite entirely in Spanish.":"");
    const resp=await fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json","anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system,messages:[{role:"user",content:"Generate the email now."}]})
    });
    if(!resp.ok)throw new Error("API "+resp.status);
    const d=await resp.json();
    const raw=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text).join("")||"";
    const labels=["SUBJECT_LINE","EMAIL_BODY"];
    const result={};
    labels.forEach((lbl,i)=>{
      const next=labels[i+1];
      const re=new RegExp("\\["+lbl+"\\]([\\s\\S]*?)(?=\\["+next+"\\]|$)");
      const m=raw.match(re);
      result[lbl]=m?m[1].trim():"";
    });
    return {raw,result,labels};
  }

  const configs={
    t3_customers:{
      label:"past customer SMS reactivation campaign via HCP Campaigns",
      context:"You are writing a reactivation TEXT MESSAGE to be sent as a bulk SMS campaign through HCP Campaigns to all past customers who have not been contacted in 6+ months. SMS must be short (under 160 characters per message). Warm, neighborly, no pressure. Ask how the prior work is holding up. Do not pitch or discount — just re-open the relationship. Include a follow-up text for non-responders and a graceful response for customers who have already hired someone else.",
      scripts:["REACTIVATION_TEXT","FOLLOW_UP_TEXT","IF_ALREADY_WITH_SOMEONE"],
    },
    t3_estimates:{
      label:"fresh estimate sent in the last 30 days",
      context:"You sent this estimate recently and have not heard back. Time kills deals — the longer you wait, the less likely they are to move forward. Reach out as a helpful expert. Offer to walk them through the pricing line by line. Show them what price transparency and genuine care actually look like. They may never have experienced it.",
      scripts:["FOLLOW_UP_CALL","FOLLOW_UP_TEXT"],
    },
    t3_calls:{
      label:"missed call or unanswered voicemail",
      context:"This person called you and got no answer. They were ready to hire someone. Every hour you wait, they get closer to calling your competitor. Call back immediately. Own the miss in one line. Then show them what a real Pro looks like: clear pricing, actual communication, respect for their home. This may be the first time they experience that.",
      scripts:["LIVE_CALLBACK","FOLLOW_UP_TEXT","IF_ALREADY_BOOKED"],
    },
  };
  const cfg=configs[bucket]||configs.t3_calls;
  const system=`You are a copywriter for home service business owners. Generate exactly 3 recovery scripts labeled exactly as: [${cfg.scripts[0]}], [${cfg.scripts[1]}], [${cfg.scripts[2]}]. Each script on its own section.

Rules: No em dashes, no en dashes, no double hyphens. No brackets or placeholders like [Name]. Every word must be ready to use as-is. Sound like a real person talking to a neighbor, not a salesperson. Short paragraphs. Blank line between each paragraph.

Core philosophy: Most homeowners have never experienced a truly great contractor. They have had their issue fixed, but they have not found their Pro for life. That is what you are offering: full price transparency, real communication, and genuine care for their home.

Context for this script type: ${cfg.context}

Generate all 3 scripts now. Trade: ${inp.trade||"home services"}. City: ${inp.city||"your area"}. Business: ${inp.businessName||"your business"}.${isEs?" Write everything in Spanish.":""}`;
  const raw=await callClaude([{role:"user",content:`Generate the 3 scripts for a ${cfg.label}.`}],system);
  // Parse out the 3 scripts
  const labels=cfg.scripts;
  const result={};
  labels.forEach((lbl,i)=>{
    const next=labels[i+1];
    const re=new RegExp(`\\[${lbl}\\]([\\s\\S]*?)(?=\\[${next}\\]|$)`);
    const m=raw.match(re);
    result[lbl]=m?m[1].trim():"";
  });
  return {raw,result,labels};
}

