// ── Email question card — Week 1 style (progress bar, chips, expandable examples) ──
function EmailQuestionCard({qNum,label,hint,chips,chipTips,urgencyTiers,examples,placeholder,inputType,val,setVal,step,total,onBack,onNext}){
  const s=useSp();
  const [showEx,setShowEx]=useState(false);

  const chipSelected=chips&&chips.includes(val);

  return (
    <Card style={{minHeight:240}}>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
        <span style={{background:NAVY,color:YELLOW,borderRadius:6,padding:"2px 10px",fontSize:12,fontWeight:900}}>Q{qNum}</span>
        <span style={{fontWeight:800,color:NAVY,fontSize:17,lineHeight:1.3}}>{label}</span>
      </div>
      {hint&&<p style={{fontSize:13,color:GRAY600,margin:"0 0 14px",lineHeight:1.7}}>{hint}</p>}

      {chips?(
        <div style={{marginBottom:14}}>
          <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:12}}>
            {chips.map((chip,i)=>{
              const sel=val===chip;
              return <button key={i} onClick={()=>setVal(sel?"":chip)}
                style={{background:sel?NAVY:GRAY50,color:sel?YELLOW:NAVY,border:"1.5px solid "+(sel?NAVY:GRAY200),borderRadius:99,padding:"7px 16px",fontSize:13,fontWeight:sel?800:600,cursor:"pointer",transition:"all 0.15s"}}>
                {sel?"✓ ":""}{chip}
              </button>;
            })}
          </div>
          {chipTips&&chipTips[val]&&(
            <div style={{background:"#F0FDF4",border:"1.5px solid "+GREEN,borderRadius:10,padding:"10px 14px",marginBottom:10,display:"flex",gap:8,alignItems:"flex-start"}}>
              <span style={{flexShrink:0}}>💡</span>
              <span style={{fontSize:13,color:"#065F46",lineHeight:1.6}}>{chipTips[val]}</span>
            </div>
          )}
          {val&&(val.includes("3 spots")||val.includes("3 espacios"))&&(
            <div style={{background:"#FEF2F2",border:"1.5px solid #FCA5A5",borderRadius:10,padding:"10px 14px",marginBottom:10,display:"flex",gap:8,alignItems:"flex-start"}}>
              <span style={{flexShrink:0}}>⚠️</span>
              <span style={{fontSize:13,color:"#991B1B",lineHeight:1.6,fontWeight:600}}>{s?"Solo usa esto si tu calendario está realmente casi lleno. La escasez falsa destruye la confianza.":"Only use this if your calendar is genuinely close to full. Fake scarcity burns trust."}</span>
            </div>
          )}
          <p style={{fontSize:12,color:GRAY400,margin:"0 0 6px"}}>{s?"¿No está en la lista? Escríbelo aquí:":"Not on the list? Type it here:"}</p>
          <FormField label="" value={chipSelected?"":val} onChange={v=>setVal(v)} placeholder={placeholder} rows={1}/>
        </div>
      ):(
        <div style={{marginBottom:14}}>
          {examples&&<div style={{marginBottom:12}}>
            <button onClick={()=>setShowEx(v=>!v)} style={{display:"inline-flex",alignItems:"center",gap:6,background:GRAY50,border:"1.5px dashed "+YELLOW,borderRadius:8,padding:"8px 16px",fontSize:13,color:NAVY,cursor:"pointer",fontWeight:700}}>
              💡 {showEx?(s?"Ocultar ejemplos":"Hide examples"):(s?"¿Necesitas ejemplos?":"Need examples?")}
            </button>
            {showEx&&<div style={{marginTop:10,background:"#FFFBEB",border:"1.5px solid "+YELLOW,borderRadius:10,padding:"14px 16px"}}>
              <div style={{fontSize:11,fontWeight:800,color:GRAY400,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:10}}>{s?"Ejemplos — úsalos solo como guía":"Example answers — use as a guide only"}</div>
              {examples.map((ex,i)=><p key={i} style={{fontSize:13,color:GRAY800,fontStyle:"italic",margin:"0 0 6px",lineHeight:1.6}}>{ex}</p>)}
            </div>}
          </div>}
          <FormField label="" value={val} onChange={v=>setVal(v)} placeholder={placeholder} rows={1} type={inputType||"text"}/>
        </div>
      )}

      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:24,paddingTop:16,borderTop:"1px solid "+GRAY200}}>
        <Btn variant="ghost" onClick={onBack} style={{minWidth:110,fontSize:14}}>{s?"← Atrás":"← Back"}</Btn>
        <span style={{fontSize:13,color:GRAY400,fontWeight:600}}>{step} / {total}</span>
        <Btn onClick={onNext} disabled={!val.trim()} style={{minWidth:110,fontSize:14}}>{s?"Siguiente →":"Next →"}</Btn>
      </div>
    </Card>
  );
}

