const SHOW_UP_AUDIT=[
  {phase:"Attire",behaviors:["I wear clean, branded gear. No hoodies, gym shorts.","I keep a change of clothes in my truck to change into as necessary in between jobs."]},
  {phase:"Prior to Arriving",behaviors:["I text 'On my Way' through Housecall Pro before arrival.","On my way text includes technician photo."]},
  {phase:"Arriving at House",behaviors:["I keep my truck exterior visibly clean.","Truck is parked in the street, not blocking driveway."]},
  {phase:"Greeting Customer",behaviors:["I greet the customer by name, with eye contact and a calm intro.","I ask permission before entering the home."]},
  {phase:"Entering the Home",behaviors:["I bring a branded doormat and place it before stepping inside.","I wear booties when entering the home."]},
  {phase:"Starting Estimate or Work",behaviors:["I explain the process clearly before I start the work.","I ask the customer if they have any concerns or priorities before I begin."]},
  {phase:"Care for Home",behaviors:["I place tools and gear on a mat or clean surface, not directly on floors.","I avoid leaning tools, ladders, or gear against walls, trim, or furniture."]},
  {phase:"Estimating or Service Call Process",behaviors:["I use HCP Cam to take photos and annotate.","I use Sales Proposal Tool to enhance my estimates."]},
  {phase:"Presentation to the Customer",behaviors:["I offer a Good, Better, and Best option when quoting.","I present the estimate on a tablet."]},
  {phase:"Leaving the Home",behaviors:["I clean the house and leave it cleaner than when I found it.","I leave behind a business card, magnets, or a leave-behind brochure."]},
];

function ShowUpAuditChecklist(){
  const s=useSp();
  const [ratings,setRatings]=useState(()=>{
    try{const v=localStorage.getItem("w3_show_up_audit");if(v)return JSON.parse(v);}catch{}
    return {};
  });

  function setRating(phaseIdx,behaviorIdx,val){
    const key=`${phaseIdx}_${behaviorIdx}`;
    setRatings(prev=>{
      const n={...prev,[key]:val};
      try{localStorage.setItem("w3_show_up_audit",JSON.stringify(n));}catch{}
      return n;
    });
  }

  const totalPossible=SHOW_UP_AUDIT.length*2*2; // 10 phases * 2 behaviors * 2 max rating
  const totalScore=Object.values(ratings).reduce((a,b)=>a+(b||0),0);
  const pct=Math.round((totalScore/totalPossible)*100);
  const passing=pct>=85;

  return (
    <div>
      <div style={{background:passing?"#F0FDF4":"#FEF2F2",border:"2px solid "+(passing?GREEN:"#FCA5A5"),borderRadius:14,padding:"14px 18px",marginBottom:16,display:"flex",alignItems:"center",gap:14}}>
        <div style={{textAlign:"center",minWidth:60}}>
          <div style={{fontWeight:900,color:passing?GREEN:RED,fontSize:28,lineHeight:1}}>{pct}%</div>
          <div style={{fontSize:11,color:GRAY400,marginTop:2}}>{s?"Puntuación":"Score"}</div>
        </div>
        <div>
          <div style={{fontWeight:800,color:NAVY,fontSize:14,marginBottom:3}}>
            {passing?(s?"✅ Pasando — Por encima del 85%":"✅ Passing — Above 85%"):(s?"⚠️ Por debajo del objetivo del 85%":"⚠️ Below the 85% target")}
          </div>
          <div style={{background:GRAY200,borderRadius:99,height:8,width:180,overflow:"hidden"}}>
            <div style={{background:passing?GREEN:YELLOW,height:8,width:pct+"%",borderRadius:99,transition:"width 0.4s"}}/>
          </div>
          <div style={{fontSize:12,color:GRAY400,marginTop:3}}>{totalScore} / {totalPossible} {s?"puntos":"points"}</div>
        </div>
      </div>

      <div style={{fontSize:12,color:GRAY600,marginBottom:12,fontStyle:"italic"}}>
        {s?"Califica cada comportamiento: 0 = Nunca, 1 = A veces, 2 = Siempre":"Rate each behavior: 0 = Never, 1 = Sometimes, 2 = Always"}
      </div>

      {SHOW_UP_AUDIT.map((phase,pi)=>(
        <div key={pi} style={{marginBottom:12,border:"1.5px solid "+GRAY200,borderRadius:14,overflow:"hidden"}}>
          <div style={{background:NAVY,padding:"10px 14px"}}>
            <span style={{color:YELLOW,fontWeight:800,fontSize:13}}>{phase.phase}</span>
          </div>
          {phase.behaviors.map((beh,bi)=>{
            const key=`${pi}_${bi}`;
            const val=ratings[key]||0;
            return (
              <div key={bi} style={{padding:"12px 14px",borderBottom:bi===0?"1px solid "+GRAY200:"none",background:WHITE}}>
                <div style={{fontSize:13,color:NAVY,lineHeight:1.6,marginBottom:8}}>{beh}</div>
                <div style={{display:"flex",gap:8}}>
                  {[0,1,2].map(r=>(
                    <button key={r} onClick={()=>setRating(pi,bi,r)}
                      style={{width:40,height:32,borderRadius:8,border:"2px solid "+(val===r?NAVY:GRAY200),
                        background:val===r?(r===0?RED:r===1?YELLOW:GREEN):WHITE,
                        color:val===r?(r===0?WHITE:NAVY):GRAY400,fontWeight:800,fontSize:13,cursor:"pointer"}}>
                      {r}
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}

