// ─────────────────────────────────────────────────────────────────────────────
// SHARED: QuestionStepper — one question per card, progress bar, Step X of Y
// Matches Week 2's Stepper pattern exactly.
// steps = [{ label, labelEs, hint, hintEs, render(s) }]
// ─────────────────────────────────────────────────────────────────────────────
function QuestionStepper({titleEmoji,title,titleEs,steps,onDone,onBack}){
  const s=useSp();
  const [idx,setIdx]=useState(0);
  const cur=steps[idx];
  const isLast=idx===steps.length-1;
  const pct=Math.round(((idx+1)/steps.length)*100);
  const canNext=cur.canNext===undefined?true:cur.canNext;

  return (
    <div>
      {/* Progress bar — matches Week 1/2 exactly */}
      <div style={{marginBottom:16}}>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:12,color:GRAY400,marginBottom:6}}>
          <span style={{fontWeight:700,color:NAVY}}>{titleEmoji} {s?titleEs:title}</span>
          <span style={{fontWeight:700,color:NAVY}}>{idx+1} / {steps.length}</span>
        </div>
        <div style={{background:GRAY200,borderRadius:99,height:18,position:"relative"}}>
          <div style={{background:YELLOW,borderRadius:99,height:18,width:Math.max(2,pct)+"%",transition:"width 0.4s",display:"flex",alignItems:"center",justifyContent:"flex-end",paddingRight:8}}>
            {pct>10&&<span style={{fontSize:11,fontWeight:800,color:NAVY}}>{pct}%</span>}
          </div>
        </div>
      </div>

      <Card>
        {/* Step badge + question label — matches Week 1/2 */}
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
          <span style={{background:NAVY,color:YELLOW,borderRadius:8,padding:"4px 12px",fontSize:14,fontWeight:900,flexShrink:0}}>
            {s?"Paso":"Step"} {idx+1}
          </span>
          <span style={{fontWeight:800,color:NAVY,fontSize:17,lineHeight:1.3}}>
            {s?(cur.labelEs||cur.label):cur.label}
          </span>
        </div>
        {/* Hint */}
        {(cur.hint||cur.hintEs)&&(
          <p style={{fontSize:13,color:GRAY600,margin:"0 0 18px",lineHeight:1.7}}>
            {s?(cur.hintEs||cur.hint):cur.hint}
          </p>
        )}
        {/* Question input — rendered by each step */}
        {cur.render(s)}

        {/* Nav */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:28,paddingTop:20,borderTop:"1px solid "+GRAY200}}>
          <Btn variant="ghost" onClick={idx===0?onBack:()=>setIdx(i=>i-1)} style={{minWidth:120,fontSize:14}}>
            {s?"← Atrás":"← Back"}
          </Btn>
          <span style={{fontSize:13,color:GRAY400,fontWeight:600}}>{idx+1} / {steps.length}</span>
          <Btn onClick={isLast?onDone:()=>setIdx(i=>i+1)} disabled={!canNext} style={{minWidth:120,fontSize:14}}>
            {s?"Siguiente →":"Next →"}
          </Btn>
        </div>
      </Card>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// SCREEN: Setup — one question at a time
// ─────────────────────────────────────────────────────────────────────────────
function SetupScreen({inputs,setInputs,onNext,onBack}){
  const s=useSp();
  const imported=getImportData();
  const hasImport=imported&&(imported.proName||imported.trade||imported.city);
  const [offered,setOffered]=useState(true); // show import offer on Q1

  function doImport(){
    if(imported) setInputs(p=>({...p,...imported}));
  }

  const steps=[
    {
      label:"What's your name?", labelEs:"¿Cuál es tu nombre?",
      hint:"First and last — exactly how you want it in your scripts.",
      hintEs:"Nombre y apellido, exactamente como quieres que aparezca en tus guiones.",
      canNext:!!(inputs.proName),
      render:(sp)=><>
        {hasImport&&offered&&(
          <div style={{background:"#F0FDF4",border:"2px solid #86EFAC",borderRadius:12,padding:"12px 16px",marginBottom:16,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <span style={{fontSize:20}}>⚡</span>
            <span style={{fontSize:13,color:NAVY,fontWeight:600,flex:1}}>
              {sp?"Encontramos datos previos:":"Found previous week data:"} <strong>{[imported.proName,imported.trade,imported.city].filter(Boolean).join(" · ")}</strong>
            </span>
            <Btn onClick={()=>{doImport();setOffered(false);}} style={{fontSize:12,minHeight:36,padding:"0 14px"}}>
              {sp?"⭐ Importar":"⭐ Import"}
            </Btn>
            <button onClick={()=>setOffered(false)} style={{background:"none",border:"none",color:GRAY400,fontSize:12,cursor:"pointer",textDecoration:"underline"}}>
              {sp?"Ignorar":"Dismiss"}
            </button>
          </div>
        )}
        <FormField label="" value={inputs.proName} onChange={v=>setInputs(p=>({...p,proName:v}))} placeholder="e.g. Marcus Webb"/>
      </>,
    },
    {
      label:"What's your trade?", labelEs:"¿Cuál es tu oficio?",
      hint:"Be specific — this appears in every script we generate.",
      hintEs:"Sé específico — aparece en cada guión que generamos.",
      canNext:!!(inputs.trade),
      render:(sp)=><FormField label="" value={inputs.trade} onChange={v=>setInputs(p=>({...p,trade:v}))} placeholder="e.g. HVAC, Plumbing, Electrical"/>,
    },
    {
      label:"What city do you serve?", labelEs:"¿Qué ciudad atiendes?",
      hint:"Your primary service area.",
      hintEs:"Tu área de servicio principal.",
      canNext:!!(inputs.city),
      render:(sp)=><FormField label="" value={inputs.city} onChange={v=>setInputs(p=>({...p,city:v}))} placeholder="e.g. East Nashville"/>,
    },
    {
      label:"What's your business name?", labelEs:"¿Cuál es el nombre de tu negocio?",
      hint:"Optional — but makes your scripts sound more personal.",
      hintEs:"Opcional — pero hace que tus guiones suenen más personales.",
      canNext:true,
      render:(sp)=><FormField label="" value={inputs.businessName} onChange={v=>setInputs(p=>({...p,businessName:v}))} placeholder="e.g. Webb Home Services"/>,
    },
  ];

  return (
    <QuestionStepper
      titleEmoji="⚙️"
      title="Quick Setup" titleEs="Configuración Rápida"
      steps={steps}
      onDone={onNext}
      onBack={onBack}
    />
  );
}

