function WeekComplete({flags,onHome}){
  const s=useSp();
  const [showConfetti,setShowConfetti]=useState(true);
  useEffect(()=>{const t=setTimeout(()=>setShowConfetti(false),4500);return()=>clearTimeout(t);},[]);
  const COLORS=[YELLOW,"#FF6B6B","#4ECDC4","#45B7D1","#96CEB4","#FFEAA7","#DDA0DD","#98D8C8"];
  const pieces=Array.from({length:60},(_,i)=>({id:i,color:COLORS[i%COLORS.length],left:Math.random()*100,delay:Math.random()*2,duration:2+Math.random()*2,size:6+Math.random()*8}));

  return (
    <div style={{position:"relative"}}>
      {showConfetti&&(
        <div style={{position:"fixed",top:0,left:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:999,overflow:"hidden"}}>
          <style>{"@keyframes fall{0%{transform:translateY(-20px) rotate(0deg);opacity:1}100%{transform:translateY(100vh) rotate(720deg);opacity:0}}"}</style>
          {pieces.map(p=><div key={p.id} style={{position:"absolute",left:p.left+"%",top:"-20px",width:p.size+"px",height:p.size+"px",background:p.color,borderRadius:p.id%3===0?"50%":"2px",animation:`fall ${p.duration}s ${p.delay}s ease-in forwards`}}/>)}
        </div>
      )}
      <div style={{background:"linear-gradient(135deg,"+NAVY+",#083072)",borderRadius:20,padding:"36px 28px",marginBottom:20,textAlign:"center"}}>
        <div style={{fontSize:64,marginBottom:8}}>🏆</div>
        <div style={{background:YELLOW,borderRadius:99,display:"inline-block",padding:"5px 18px",marginBottom:12}}>
          <span style={{color:NAVY,fontWeight:900,fontSize:13,letterSpacing:"0.05em"}}>{s?"SEMANA 3 COMPLETADA":"WEEK 3 COMPLETE"}</span>
        </div>
        <h1 style={{color:YELLOW,fontSize:24,fontWeight:900,margin:"0 0 10px",lineHeight:1.2}}>
          {s?"Cerraste las fugas. Recuperaste los ingresos.":"You plugged the leaks. You recovered revenue."}
        </h1>
        <p style={{color:"rgba(255,255,255,0.85)",fontSize:14,lineHeight:1.8,margin:0}}>
          {s?"Mientras todos persiguen nuevos prospectos, tú estás ganando más del embudo que ya tienes.":"While everyone chases new leads, you're winning more from the funnel you already have."}
        </p>
      </div>

      <div style={{background:WHITE,border:"1.5px solid "+GRAY200,borderRadius:16,padding:"18px 20px",marginBottom:16}}>
        <h3 style={{color:NAVY,fontWeight:900,fontSize:16,margin:"0 0 14px"}}>{s?"Lo que ejecutaste:":"What you executed:"}</h3>
        {[
          {emoji:"📞",title:s?"Embudo Superior":"Top Funnel",desc:s?`${flags.missedCallsWorked||0} llamadas de recuperación / textos enviados`:`${flags.missedCallsWorked||0} recovery calls / texts sent`},
          {emoji:"📋",title:s?"Embudo Medio":"Mid Funnel",desc:s?`${flags.estimatesFollowedUp||0} cotizaciones con seguimiento`:`${flags.estimatesFollowedUp||0} estimates followed up`},
          {emoji:"💤",title:s?"Embudo Inferior":"Bottom Funnel",desc:s?`${flags.dormantReactivated||0} clientes dormidos contactados`:`${flags.dormantReactivated||0} dormant customers contacted`},
          {emoji:"💼",title:s?"Trabajos Reservados":"Jobs Booked",desc:s?`${flags.jobsBooked||0} trabajos de la estrategia de recuperación`:`${flags.jobsBooked||0} jobs from recovery strategy`},
        ].map((item,i)=>(
          <div key={i} style={{display:"flex",gap:12,alignItems:"flex-start",background:GRAY50,borderRadius:12,padding:"12px 14px",marginBottom:i<3?8:0}}>
            <span style={{fontSize:20,flexShrink:0}}>{item.emoji}</span>
            <div>
              <div style={{fontWeight:800,color:NAVY,fontSize:13,marginBottom:2}}>{item.title}</div>
              <div style={{fontSize:12,color:GRAY600,lineHeight:1.5}}>{item.desc}</div>
            </div>
          </div>
        ))}
      </div>

      <div style={{background:"#001833",border:"2px solid "+YELLOW,borderRadius:16,padding:"20px 20px",marginBottom:20}}>
        <div style={{fontSize:36,textAlign:"center",marginBottom:10}}>🎣</div>
        <p style={{color:WHITE,fontSize:14,lineHeight:1.8,margin:"0 0 12px",textAlign:"center"}}>
          {s?"Cada trabajo reservado esta semana no te costó ni un centavo en publicidad. Solo requirió scripts mejores, mejor momento, y seguimiento real.":"Every job you booked this week cost you zero dollars in advertising. It just required better scripts, better timing, and real follow-through."}
        </p>
        <div style={{background:"rgba(254,183,6,0.12)",border:"1.5px solid "+YELLOW,borderRadius:10,padding:"12px 14px",textAlign:"center"}}>
          <p style={{color:YELLOW,fontWeight:900,fontSize:14,margin:0}}>
            {s?"Ahora ve a trabajar esos prospectos.":"Now go work those leads."}
          </p>
        </div>
      </div>

      <div style={{textAlign:"center"}}>
        <Btn onClick={onHome} variant="secondary" style={{fontSize:14}}>
          {s?"← Todas las Semanas":"← All Weeks"}
        </Btn>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN Week3App
// ─────────────────────────────────────────────────────────────────────────────
export function Week3App({onHome}){
  const [phase,setPhaseRaw]=useState(()=>{
    const p=lsGet(LS_PHASE,"home");
    return W3_PHASES.has(p)?p:"home";
  });
  const [flags,setFlagsRaw]=useState(()=>({...DEF_FLAGS,...lsGet(LS_FLAGS,{})}));
  const [inputs,setInputsRaw]=useState(()=>({...DEF_INPUTS,...lsGet(LS_INPUTS,{})}));
  const [lang,setLang]=useState(()=>lsGet("hcp_w3_lang","en"));

  const topRef=useRef(null);

  function setPhase(p){setPhaseRaw(p);lsSet(LS_PHASE,p);}
  function setFlag(k,v){setFlagsRaw(prev=>{const n={...prev,[k]:v};lsSet(LS_FLAGS,n);return n;});}
  function setInputs(fn){setInputsRaw(prev=>{const n=typeof fn==="function"?fn(prev):{...prev,...fn};lsSet(LS_INPUTS,n);return n;});}
  function switchLang(l){setLang(l);lsSet("hcp_w3_lang",l);}

  useEffect(()=>{if(topRef.current)topRef.current.scrollIntoView({behavior:"smooth"});},[phase]);

  const activeSection=NAV.find(n=>n.phases.includes(phase));
  const isHome=phase==="home"||phase==="setup";
  const s=lang==="es";

  const [assessRestartModal,setAssessRestartModal]=useState(false);

  function nav(id,sub){
    if(id==="assessment"&&sub){
      // Sub-menu click: jump to specific step
      setInputs(p=>({...p,_assessJump:sub}));
      setPhase("assessment");
    } else if(id==="assessment"&&!sub){
      // Top-level Assessment click: if they've started before, ask what to do
      const hasProgress=inputs.assessmentComplete||inputs.assessmentStep;
      if(hasProgress){
        setAssessRestartModal(true);
      } else {
        setPhase("assessment");
      }
    } else if(sub&&W3_PHASES.has(sub)){
      setPhase(sub);
    } else if(W3_PHASES.has(id)){
      setPhase(id);
    } else {
      const firstPhase=NAV.find(n=>n.id===id)?.phases[0];
      if(firstPhase&&W3_PHASES.has(firstPhase))setPhase(firstPhase);
    }
  }

  return (
    <LangCtx.Provider value={lang}>
      <style>{`
        input[type=range]{-webkit-appearance:none;appearance:none;width:100%;height:6px;border-radius:99px;background:#CBD5E1;outline:none;cursor:pointer;display:block;margin:10px 0;}
        input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;appearance:none;width:26px;height:26px;border-radius:50%;background:#0A2443;cursor:pointer;box-shadow:0 2px 8px rgba(10,36,67,0.35);border:3px solid #fff;margin-top:-10px;}
        input[type=range]::-moz-range-thumb{width:26px;height:26px;border-radius:50%;background:#0A2443;cursor:pointer;box-shadow:0 2px 8px rgba(10,36,67,0.35);border:3px solid #fff;box-sizing:border-box;}
        input[type=range]::-webkit-slider-runnable-track{height:6px;border-radius:99px;background:#CBD5E1;}
        input[type=range]::-moz-range-track{height:6px;border-radius:99px;background:#CBD5E1;}
      `}</style>

      {/* Assessment restart modal */}
      {assessRestartModal&&(
        <div style={{position:"fixed",inset:0,background:"rgba(10,36,67,0.6)",zIndex:999,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
          <div style={{background:WHITE,borderRadius:20,padding:"32px 28px",maxWidth:420,width:"100%",boxShadow:"0 8px 40px rgba(0,0,0,0.25)"}}>
            <div style={{fontSize:32,textAlign:"center",marginBottom:12}}>🔍</div>
            <div style={{fontWeight:900,color:NAVY,fontSize:18,textAlign:"center",marginBottom:8}}>
              {s?"¿Volver a hacer la evaluación?":"Redo the assessment?"}
            </div>
            <p style={{fontSize:14,color:GRAY600,textAlign:"center",lineHeight:1.7,margin:"0 0 24px"}}>
              {s?"Ya tienes una evaluación guardada. ¿Quieres empezar desde cero o continuar donde lo dejaste?":"You have a saved assessment. Do you want to start fresh or pick up where you left off?"}
            </p>
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              <button onClick={()=>{
                // Reset all assessment-related inputs to defaults
                setInputs(p=>({
                  ...p,
                  assessmentStep:null,assessmentComplete:false,
                  tc:undefined,mc:undefined,handling:null,selfBehavior:null,
                  csrCost:undefined,answerSolution:null,csrAiConfig:null,hcpAssistConfig:null,
                  callBookingRate:undefined,closeRate:undefined,openEstimates:undefined,
                  avgJobSize:undefined,usesPipeline:null,customerCount:undefined,
                  jobsPerYear:undefined,hasDripCampaign:null,
                  _assessJump:"__plinko__",
                }));
                setAssessRestartModal(false);
                setPhase("assessment");
              }} style={{background:NAVY,border:"none",borderRadius:12,padding:"14px",color:WHITE,fontWeight:800,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>
                🔄 {s?"Empezar desde cero":"Start fresh"}
              </button>
              <button onClick={()=>{
                setAssessRestartModal(false);
                setPhase("assessment");
              }} style={{background:WHITE,border:"2px solid "+NAVY,borderRadius:12,padding:"14px",color:NAVY,fontWeight:800,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>
                ↩ {s?"Continuar donde lo dejé":"Continue where I left off"}
              </button>
              <button onClick={()=>setAssessRestartModal(false)}
                style={{background:"none",border:"none",fontSize:13,color:GRAY400,cursor:"pointer",padding:"6px",fontFamily:"inherit"}}>
                {s?"Cancelar":"Cancel"}
              </button>
            </div>
          </div>
        </div>
      )}

      <div style={{minHeight:"100vh",background:GRAY50,fontFamily:"'Inter',-apple-system,sans-serif"}}>
        {/* Header — matches Week 2 exactly */}
        <div style={{background:NAVY,padding:"16px 24px",display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:100,boxShadow:"0 2px 12px rgba(0,0,0,0.2)"}}>
          <div style={{display:"flex",alignItems:"center",gap:14}}>
            <button onClick={()=>{ if(onHome) onHome(); else setPhase("home"); }} style={{background:YELLOW,border:"none",borderRadius:10,padding:"8px 16px",color:NAVY,fontWeight:900,fontSize:14,cursor:"pointer",whiteSpace:"nowrap"}}>
              {s?"← Todas las Semanas":"← All Weeks"}
            </button>
            <div>
              <div style={{color:WHITE,fontWeight:800,fontSize:16,lineHeight:1}}>Business Coaching Foundations</div>
              <div style={{color:"#00B246",fontSize:12,fontWeight:600}}>
                {s?"Semana 3 — La Estrategia de Recuperación de Trabajos":"Week 3 — The Job Recovery Strategy"}
              </div>
            </div>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{display:"flex",borderRadius:8,overflow:"hidden",border:"1.5px solid rgba(255,255,255,0.2)"}}>
              {["en","es"].map(l=>(
                <button key={l} onClick={()=>switchLang(l)}
                  style={{padding:"6px 14px",fontWeight:700,fontSize:13,border:"none",cursor:"pointer",
                    background:lang===l?YELLOW:"transparent",color:lang===l?NAVY:WHITE,transition:"all 0.2s"}}>
                  {l.toUpperCase()}
                </button>
              ))}
            </div>
            <button onClick={()=>setPhase("home")}
              style={{background:YELLOW,border:"none",borderRadius:8,padding:"8px 18px",color:NAVY,fontSize:13,fontWeight:800,cursor:"pointer",marginLeft:16}}>
              {s?"Guardar y Salir":"Save & Exit"}
            </button>
          </div>
        </div>

        {/* Body */}
        <div ref={topRef} style={{display:"flex",minHeight:"calc(100vh - 68px)"}}>
          {/* Sidebar — hide on home */}
          {!isHome&&(
            <SideNav current={phase} onNavigate={nav} flags={flags} inputs={inputs}/>
          )}

          {/* Main content — matches Week 2 inner phase padding */}
          <div style={{flex:1,padding:isHome?"28px 24px 60px":"28px 40px 60px",minWidth:0,display:"flex",flexDirection:"column",alignItems:"center"}}>
            <div style={{width:"100%",maxWidth:isHome?960:720}}>
            {phase==="assessment"&&<AssessmentScreen inputs={inputs} setInputs={setInputs} onBack={()=>setPhase("home")} onNext={()=>setPhase("t3_intro")} jumpTo={inputs._assessJump} onJumpConsumed={()=>setInputs(p=>({...p,_assessJump:null}))}/>}
            {phase==="home"&&<HomeScreen onStart={()=>setPhase("setup")} onNavigate={nav} flags={flags}/>}
            {phase==="setup"&&<SetupScreen inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("t3_intro")} onBack={()=>setPhase("home")}/>}

            {/* ⭐ Top 3 Plays */}
            {phase==="t3_intro"           &&<T3Intro             onNext={()=>setPhase("t3_customers_intro")} onBack={()=>setPhase("home")}/>}
            {phase==="t3_customers_intro" &&<T3CustomersIntro    inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("t3_customers_plug")} onBack={()=>setPhase("t3_intro")}/>}
            {phase==="t3_customers_plug"   &&<T3CustomersPlug    onNext={()=>setPhase("t3_customers_script")} onBack={()=>setPhase("t3_customers_intro")}/>}
            {phase==="t3_customers_script"&&<T3CustomersScript   inputs={inputs} setFlag={setFlag} onNext={()=>setPhase("t3_estimates_intro")} onBack={()=>setPhase("t3_customers_plug")}/>}
            {phase==="t3_estimates_intro" &&<T3EstimatesIntro    onNext={()=>setPhase("t3_estimates_fix")} onBack={()=>setPhase("t3_customers_script")}/>}
            {phase==="t3_estimates_fix"   &&<T3EstimatesFix      onNext={()=>setPhase("t3_estimates_script")} onBack={()=>setPhase("t3_estimates_intro")}/>}
            {phase==="t3_estimates_script"&&<T3EstimatesScript   inputs={inputs} setFlag={setFlag} onNext={()=>setPhase("t3_calls_intro")} onBack={()=>setPhase("t3_estimates_fix")}/>}
            {phase==="t3_calls_intro"     &&<T3CallsIntro        onNext={()=>setPhase("t3_calls_fix")} onBack={()=>setPhase("t3_estimates_script")}/>}
            {phase==="t3_calls_fix"       &&<T3CallsFix          inputs={inputs} onNext={()=>setPhase("t3_calls_script")} onBack={()=>setPhase("t3_calls_intro")}/>}
            {phase==="t3_calls_script"    &&<T3CallsScript       inputs={inputs} setFlag={setFlag} onNext={()=>setPhase("t3_goal_complete")} onBack={()=>setPhase("t3_calls_fix")}/>}
            {phase==="t3_goal_complete"   &&<T3GoalComplete      flags={flags} setFlag={setFlag} onNavigate={nav} onBack={()=>setPhase("t3_calls_script")}/>}

            {/* Top Funnel */}
            {phase==="top_intro"&&<TopIntro onNext={()=>setPhase("top_calls_intro")} onBack={()=>setPhase("home")}/>}
            {phase==="top_calls_intro"  &&<TopCallsIntro   onNext={()=>setPhase("top_calls_fix")}   onBack={()=>setPhase("top_intro")}/>}
            {phase==="top_calls_fix"    &&<TopCallsFix     inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("top_calls_script")}   onBack={()=>setPhase("top_calls_intro")}/>}
            {phase==="top_calls_script" &&<TopCallsScript  inputs={inputs} setFlag={setFlag}         onNext={()=>setPhase("top_email_intro")}  onBack={()=>setPhase("top_calls_fix")}/>}
            {phase==="top_email_intro"  &&<TopEmailIntro   onNext={()=>setPhase("top_email_fix")}   onBack={()=>setPhase("top_calls_script")}/>}
            {phase==="top_email_fix"    &&<TopEmailFix     inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("top_email_script")}   onBack={()=>setPhase("top_email_intro")}/>}
            {phase==="top_email_script" &&<TopEmailScript  inputs={inputs} setFlag={setFlag}         onNext={()=>setPhase("top_chat_intro")}   onBack={()=>setPhase("top_email_fix")}/>}
            {phase==="top_chat_intro"   &&<TopChatIntro    onNext={()=>setPhase("top_chat_fix")}    onBack={()=>setPhase("top_email_script")}/>}
            {phase==="top_chat_fix"     &&<TopChatFix      inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("top_chat_script")}    onBack={()=>setPhase("top_chat_intro")}/>}
            {phase==="top_chat_script"  &&<TopChatScript   inputs={inputs} setFlag={setFlag}         onNext={()=>setPhase("top_social_intro")} onBack={()=>setPhase("top_chat_fix")}/>}
            {phase==="top_social_intro" &&<TopSocialIntro  onNext={()=>setPhase("top_social_fix")}  onBack={()=>setPhase("top_chat_script")}/>}
            {phase==="top_social_fix"   &&<TopSocialFix    inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("top_social_script")} onBack={()=>setPhase("top_social_intro")}/>}
            {phase==="top_social_script"&&<TopSocialScript inputs={inputs} setFlag={setFlag}         onNext={()=>{setFlag("topFunnelDone",true);setPhase("mid_intro");}} onBack={()=>setPhase("top_social_fix")}/>}

            {/* Mid Funnel */}
            {phase==="mid_intro"         &&<MidIntro         onNext={()=>setPhase("mid_fresh_intro")}   onBack={()=>setPhase("top_social_script")}/>}
            {phase==="mid_fresh_intro"   &&<MidFreshIntro    onNext={()=>setPhase("mid_fresh_fix")}     onBack={()=>setPhase("mid_intro")}/>}
            {phase==="mid_fresh_fix"     &&<MidFreshFix      inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("mid_fresh_script")}   onBack={()=>setPhase("mid_fresh_intro")}/>}
            {phase==="mid_fresh_script"  &&<MidFreshScript   inputs={inputs} setFlag={setFlag}           onNext={()=>setPhase("mid_stale_intro")}  onBack={()=>setPhase("mid_fresh_fix")}/>}
            {phase==="mid_stale_intro"   &&<MidStaleIntro    onNext={()=>setPhase("mid_stale_fix")}     onBack={()=>setPhase("mid_fresh_script")}/>}
            {phase==="mid_stale_fix"     &&<MidStaleFix      inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("mid_stale_script")}   onBack={()=>setPhase("mid_stale_intro")}/>}
            {phase==="mid_stale_script"  &&<MidStaleScript   inputs={inputs} setFlag={setFlag}           onNext={()=>setPhase("mid_closed_intro")} onBack={()=>setPhase("mid_stale_fix")}/>}
            {phase==="mid_closed_intro"  &&<MidClosedIntro   onNext={()=>setPhase("mid_closed_fix")}    onBack={()=>setPhase("mid_stale_script")}/>}
            {phase==="mid_closed_fix"    &&<MidClosedFix     inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("mid_closed_script")}  onBack={()=>setPhase("mid_closed_intro")}/>}
            {phase==="mid_closed_script" &&<MidClosedScript  inputs={inputs} setFlag={setFlag}           onNext={()=>{setFlag("midFunnelDone",true);setPhase("bottom_intro");}} onBack={()=>setPhase("mid_closed_fix")}/>}

            {/* Bottom Funnel */}
            {phase==="bottom_intro"            &&<BottomIntro           onNext={()=>setPhase("bottom_customers_intro")} onBack={()=>setPhase("mid_closed_script")}/>}
            {phase==="bottom_customers_intro"  &&<BottomCustomersIntro  onNext={()=>setPhase("bottom_customers_fix")}   onBack={()=>setPhase("bottom_intro")}/>}
            {phase==="bottom_customers_fix"    &&<BottomCustomersFix    inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("bottom_customers_script")} onBack={()=>setPhase("bottom_customers_intro")}/>}
            {phase==="bottom_customers_script" &&<BottomCustomersScript inputs={inputs} setFlag={setFlag}     onNext={()=>setPhase("bottom_referrals_intro")}  onBack={()=>setPhase("bottom_customers_fix")}/>}
            {phase==="bottom_referrals_intro"  &&<BottomReferralsIntro  onNext={()=>setPhase("bottom_referrals_fix")}   onBack={()=>setPhase("bottom_customers_script")}/>}
            {phase==="bottom_referrals_fix"    &&<BottomReferralsFix    inputs={inputs} setInputs={setInputs} onNext={()=>setPhase("bottom_referrals_script")} onBack={()=>setPhase("bottom_referrals_intro")}/>}
            {phase==="bottom_referrals_script" &&<BottomReferralsScript inputs={inputs} setFlag={setFlag}     onNext={()=>setPhase("scorecard")}               onBack={()=>setPhase("bottom_referrals_fix")}/>}

            {/* Scorecard + Complete */}
            {phase==="scorecard"    &&<Scorecard    flags={flags} setFlag={setFlag} onNext={()=>setPhase("week_complete")} onBack={()=>setPhase("bottom_referrals_script")}/>}
            {phase==="week_complete"&&<WeekComplete flags={flags} onHome={onHome}/>}
            </div>{/* maxWidth wrapper */}
          </div>{/* flex:1 content */}
        </div>{/* flex body */}
      </div>
    </LangCtx.Provider>
  );
}

export default Week3App;
